import React, { useState } from "react";
import ReactDOM from "react-dom/client";
import { BrowserRouter, Route, Routes } from "react-router-dom";
import { createTheme, ThemeProvider } from "@mui/material/styles";
import CssBaseline from "@mui/material/CssBaseline";
import "./index.css";
import Home from "./components/Home";

function Root() {
  // 1. Manage global dark theme state
  const [darkMode, setDarkMode] = useState(false);

  // 2. Build the Material-UI theme configurations engine
  const theme = createTheme({
    palette: {
      mode: darkMode ? "dark" : "light",
      background: {
        default: darkMode ? "#121212" : "#ffffff",
        paper: darkMode ? "#1e1e1e" : "#ffffff",
      },
      text: {
        primary: darkMode ? "#ffffff" : "#000000",
        secondary: darkMode ? "#aaaaaa" : "#666666",
      },
    },
  });

  return (
    <ThemeProvider theme={theme}>
      {/* CssBaseline guarantees the body background color responds to the theme switch */}
      <CssBaseline />
      <BrowserRouter>
        <Routes>
          {/* 3. Pass theme state and switches down to your Home layout */}
          <Route
            path="/*"
            element={<Home darkMode={darkMode} setDarkMode={setDarkMode} />}
          />
        </Routes>
      </BrowserRouter>
    </ThemeProvider>
  );
}

const root = ReactDOM.createRoot(document.getElementById("root"));
root.render(
  <React.StrictMode>
    <Root />
  </React.StrictMode>,
);
